public function routePush(Request $request)
{
    // 1. 验证IP白名单
    $allowedIPs = config('services.sf.express.callback_ips', []);
    if (!in_array($request->ip(), $allowedIPs)) {
        return response('<Response><Head>ERR</Head></Response>', 403);
    }

    // 2. 验证签名
    if (!$this->sfService->verifySignature($request->all())) {
        return response('<Response><Head>ERR</Head></Response>', 403);
    }

    // 3. 处理业务逻辑
    // ...
}

