$affectedRows = User::where('id', $userId)
    ->where('version', $currentVersion)
    ->update([
        'balance' => $newBalance,
        'version' => $currentVersion + 1,
    ]);

if ($affectedRows === 0) {
    throw new ConcurrencyException('数据已被修改，请重试');
}

